TriggerOraclev10g.body:
DECLARE
    v_codigo VARCHAR2(30);
BEGIN  
    IF :new.id_prestador_salud IS NULL THEN
        :new.id_prestador_salud := 0;
    END IF;
    IF :new.id IS NULL THEN
        v_codigo := pkgca_tkr_codigos_descuentos.f_generar_codigo;
        IF trunc(:new.fecha_nacimiento) > trunc(f_fecha_actual) THEN
            raise_application_error(-20001, 'No se permite ingresar una fecha de nacimiento mayor a la fecha actual.');
        END IF;     
        :new.usuario := lower(trim(:new.usuario));
        :new.fecha_creacion := SYSTIMESTAMP AT TIME ZONE 'America/Bogota';
        :new.id := tkr_usuarios_seq.nextval;  
        :new.codigo_referencia := v_codigo;
        IF :new.id_usuario_creacion IS NULL THEN 
            :new.id_usuario_creacion := :new.id; 
        END IF; 
        IF :new.id_perfil_doctor IS NULL and :new.id_rol = 4 THEN 
            :new.id_perfil_doctor := 1; 
        END IF;
    END IF; 
END;
